import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Home from './pages/Home';
import Scenarios from './pages/Scenarios';
import Courtroom from './pages/Courtroom';
import Dashboard from './pages/Dashboard';
import MultiplayerPage from './pages/MultiplayerPage';
import MarketplacePage from './pages/MarketplacePage';
import About from './pages/About';
import Contact from './pages/Contact';
import Login from './pages/Login';
import Test from './pages/Test';
import CreateScenario from './pages/CreateScenario';
import PaymentPage from './pages/PaymentPage';
import CartPage from './pages/CartPage';
import LegalAnalysis from './pages/LegalAnalysis'; // Added import
import { UserProvider } from './contexts/UserContext'; // Added import
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import TestScenarios from './components/TestScenarios';

function App() {
  return (
    <Router>
      <UserProvider>
        <div className="min-h-screen bg-gray-50">
          <Navbar />
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/scenarios" element={<Scenarios />} />
            <Route path="/courtroom" element={<Courtroom />} />
            <Route path="/dashboard" element={<Dashboard />} />
            <Route path="/multiplayer" element={<MultiplayerPage />} />
            <Route path="/marketplace" element={<MarketplacePage />} />
            <Route path="/about" element={<About />} />
            <Route path="/contact" element={<Contact />} />
            <Route path="/login" element={<Login />} />
            <Route path="/test" element={<Test />} />
            <Route path="/test-scenarios" element={<TestScenarios />} />
            <Route path="/create-scenario" element={<CreateScenario />} />
            <Route path="/payment" element={<PaymentPage />} />
            <Route path="/cart" element={<CartPage />} />
            <Route path="/legal-analysis" element={<LegalAnalysis />} /> {/* Added route */}
          </Routes>
          <Footer />
        </div>
      </UserProvider>
    </Router>
  );
}

export default App;
